var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"역시 정말로 자네였나, 스완.","JPN":"やはり君だったのか、スワン。","ENG":"So it really was you, Swan.","TWN":"果然真的是你，史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 이방인들의 말이 사실이었어. 정말로 이렇게 스완이 나타날 줄이야.","JPN":"異邦人たちの話は本当だった。本当にこうやってスワンが現れるとは。","ENG":"What those outsiders said was true. I never imagined you'd show up like this.","TWN":"那些外邦人說的是真的。沒想到史旺真的會出現。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그것도 이렇게나 성장한 모습으로 말이지. 이거 예상했던 것보다 훨씬 감회가 새롭군.","JPN":"それもこんなに成長した姿で。予想していたよりもずっと感慨深いものだな。","ENG":"And looking so grown-up, too. This hits a lot harder than I expected.","TWN":"而且看起來這麼成熟，這感覺比我預想的還要強烈。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서? 그동안 어떻게 지냈나?","JPN":"それで？　元気だったかね？","ENG":"So? How have you been all this time?","TWN":"那麼？這段時間你過得怎麼樣？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"딱히…….","JPN":"別に……","ENG":"Well...","TWN":"嗯……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"잘 지냈다고 말은 못하겠군요.","JPN":"元気だったとは言えませんね。","ENG":"I can't say I've been doing very well.","TWN":"說不上過得很好。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 그 우산은 틀림없이 내 마도구로군.","JPN":"おお、その傘は私の魔道具だな。","ENG":"Wait, that umbrella is my Curio, isn't it?","TWN":"等等，那把傘是我的魔法道具，對吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"알고 있나? 그건 어떤 충격이라도 한 번은 사용자를 지켜주는 마도구야.","JPN":"知っているかい？　それはどんな衝撃からも一度は使用者を守ってくれる魔道具なのだ。","ENG":"Do you know? It's a Curio that protects the user from any single shock.","TWN":"你知道嗎？那是一個能保護使用者免受任何一次衝擊的魔法道具。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그걸 가지고 있다는 뜻은… 설마 그 우산이 자네 목숨을 지켜준 적이 있다는 뜻인가……?","JPN":"それを持っているということは……傘が君の命を守ったことがあったということだろうか……？","ENG":"If you've got it, then... does it mean that it saved your life once...?","TWN":"如果你還留著它……是不是表示它曾經救過你一命……？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그렇다면 정말로 기쁠 텐데 말이지.","JPN":"ふふ、それなら本当に嬉しいが。","ENG":"Haha, if that's true, then I'm really glad.","TWN":"哈哈，如果是真的，那我真的很高興。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……아니요.","JPN":"……いいえ。","ENG":"...No.","TWN":"……沒有。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 물려받았던 시점에서 이건 이미 용도를 다한 평범한 우산이었답니다.","JPN":"私が譲り受けた時点で、すでにその役を終えた普通の傘でした。","ENG":"By the time I inherited it, it was already just an ordinary umbrella.","TWN":"等我繼承它的時候，它已經只是一把普通的傘了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래? 그거 아쉽게 됐군.","JPN":"そうなのか？　それは残念だ。","ENG":"Really? That's a shame.","TWN":"真的嗎？那真可惜。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그래도 지금까지 소중하게 간직해 주어서 무척 기쁘다네.","JPN":"だが、それでも今まで大事にしてくれてとても嬉しい。","ENG":"Still, I'm truly grateful you've treasured it until now.","TWN":"不過，我真的很感激你一直珍惜著它。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그건 그렇고 어느새 키가 훌쩍 자라버렸군.","JPN":"ふふ、それはそうとして、いつの間にか背が伸びたんたな。","ENG":"Haha, and look at you now. You've grown so tall.","TWN":"哈哈，看看你現在，長得真高了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이제는 정말로 훌륭한 레이디라고 불러도 손색이 없겠어.","JPN":"もう立派なレディーと呼んでもいいくらいだ。","ENG":"You've become a proper lady, without a doubt.","TWN":"你絕對是一位真正的淑女了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러는 당신은 여전히 제 기억 속 그 모습 그대로군요.","JPN":"そういうあなたは、相変わらず私の記憶の中のままですね。","ENG":"And yet you look exactly the same as you do in my memory.","TWN":"但你看起來和我記憶中的一模一樣。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"뭐, 그야 그렇겠지.","JPN":"まあ、それはそうだろう。","ENG":"Well, that makes sense.","TWN":"嗯，那也說得通。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"애초에 이 세계는 자네의 <color=#ffd34c>기억</color>으로부터 재창조된 허상에 불과하지 않은가?","JPN":"そもそもこの世界は君の<color=#ffd34c>記憶</color>から再創造された虚像に過ぎない。","ENG":"This world is nothing but an illusion recreated from your <color=#ffd34c>memories</color>, isn't it?","TWN":"這個世界不過是從你的<color=#ffd34c>記憶</color>中重現的幻象，不是嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"줄곧 이상하다고 생각했다네, 스완.","JPN":"ずっとおかしいとは思っていた、スワン。","ENG":"It's always bothered me, Swan.","TWN":"我一直覺得很奇怪，史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 이방인들의 말이 사실이라면…….","JPN":"異邦人たちの話が本当なら……","ENG":"If what those outsiders said is true...","TWN":"如果那些外邦人說的是真的……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 자네가 정말로 모든 걸 돌이킬 수 있는 힘을 얻게 되었다면…….","JPN":"そして君が本当に全てを元に戻せる力を手に入れたのなら……","ENG":"And if you really did gain the power to undo everything...","TWN":"如果你真的獲得了能夠扭轉一切的力量……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어째서 심야의 살인마 사건이 발생한 시점으로 세계를 되돌릴 수밖에 없었는지 말이야.","JPN":"なぜ深夜の殺人鬼事件が発生した時点にしか世界を戻さないのか。","ENG":"Why did you choose to rewind the world to the time of the Midnight Killer case?","TWN":"為什麼世界只能回到午夜殺人魔事件發生的時間點呢。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"간단한 이야기라네, 스완.","JPN":"簡単な話だ、スワン。","ENG":"It's simple, my dear Swan.","TWN":"這很簡單，史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"애초부터 자네는 이럴 수밖에 없었던 거야.","JPN":"初めから君はこうするしかなかったのだ。","ENG":"You never had a choice.","TWN":"從一開始你就只能這樣。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계는 자네의 <color=#ffd34c>기억</color>을 바탕으로 존재할 수밖에 없으니까.","JPN":"この世界は君の<color=#ffd34c>記憶</color>をもとに存在するしかないからね。","ENG":"This world can only exist based on your <color=#ffd34c>memories</color>.","TWN":"這個世界只能以你的<color=#ffd34c>記憶</color>為基礎而存在。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"확실히 자네는 완전 기억 능력을 가졌어.","JPN":"確かに、君は完全記憶能力を持っている。","ENG":"You really do have perfect memory.","TWN":"確實，你擁有完全的記憶能力。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"분명 내가 가늠하는 것보다도 훨씬 정확하고 방대한 양의 정보를 기억하겠지.","JPN":"きっと私が推測しているよりもずっと、正確で膨大な量の情報を記憶しているのだろう。","ENG":"You probably remember far more than I could ever imagine.","TWN":"肯定比我估計的要記住更準確和龐大的資訊量。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 자네라도 모든 걸 알지는 못해. 자네가 경험하지 못한 건 기억할 수 없지.","JPN":"だが、君であっても全てを知ることはできない。君が経験できなかったことは記憶できないからな。","ENG":"But even you don't know everything. You can't remember what you've never experienced.","TWN":"但是即使是你也不可能知道一切。你沒有經歷過的事情是無法記住的。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 이 세계에서 자네의 기억 밖에 있는 것은 존재할 수 없어.","JPN":"そして、この世界で君の記憶にないものは存在できない。","ENG":"And anything outside your memory doesn't exist in this world.","TWN":"而在這個世界上，只有你記憶之外的東西無法存在。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 이를테면… 자네의 기억 밖에 존재하는 풍경…….","JPN":"そう、たとえば……君の記憶にない風景……","ENG":"Yes, for instance... the scenery beyond your memories...","TWN":"是的，比如說……存在於你記憶之外的風景……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내 예상이 맞다면 이 도시, 런던 밖의 세계는 멸망한 세계의 풍경 그대로 일 거야.","JPN":"私の予想どおりならこの都市、ロンドンの外の世界は滅亡した世界の風景そのままであるはずだ。","ENG":"If I'm right, then everything outside this city, outside London, is exactly how the world looked after its collapse.","TWN":"如果我的預想沒錯的話，這座城市，倫敦之外的世界，將會是滅亡世界的景象。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇지 않나, 스완?","JPN":"そうだろう、スワン？","ENG":"Isn't that right, Swan?","TWN":"對吧，史旺？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그 세피라의 힘이라는 게 얼마나 대단한 건지는 모르겠지만…….","JPN":"そのセフィラの力というものがどれほどすごいものなのかは知らないが……","ENG":"I don't know how impressive Sephira's power really is...","TWN":"那個叫做生命樹的力量到底有多厲害，我也不太清楚……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"기껏해야 도시 하나짜리 불완전한 세계.","JPN":"できても都市1個分の不完全な世界。","ENG":"But this is still just an incomplete world, barely holding one city together.","TWN":"充其量也不過是一個城市大小的不完整世界。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네는 어쩔 수 없이 이 시점으로 세계를 되돌릴 수밖에 없었던 거겠지.","JPN":"君は仕方なく、この時点に世界を戻すしかなかったのだよ。","ENG":"You had no choice but to reset the world to this moment in time.","TWN":"你也只能無奈地將世界倒退到這個時間點吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 이 시점의 세계는 이미 임계치에 다다라 버린 세계야.","JPN":"だがこの時点ですでに、世界は臨界値に達している。","ENG":"But this world was already at its limit by that point.","TWN":"但此時的世界已經達到了臨界點。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"결과적으로 종말을 돌이키기에는 너무나 늦어버린 시점이지.","JPN":"結果的に、終末を避けるにはあまりにも遅すぎる時点だ。","ENG":"Too far gone to reverse the end.","TWN":"從結果上看，已經太晚了，無法逆轉終結。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과연…….","JPN":"なるほど……","ENG":"Indeed...","TWN":"果然……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후… 정말이지…….","JPN":"ふふ……まったく……","ENG":"Haha... Oh, you...","TWN":"呵呵……是的……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신 또한 제 기억으로부터 만들어진 존재에 불과할 텐데…….","JPN":"あなたも私の記憶から作られた存在に過ぎないはずなのに……","ENG":"You should be nothing but a construct born from my memory...","TWN":"你也不過是我記憶中創造出來的存在而已……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 이렇게 쉽게 수수께끼를 풀어내다니… 당신은 여전히 저를 놀라게 하는 군요.","JPN":"こうも簡単に謎を解いてしまうなんて……あなたは相変わらず私を驚かせてくれますね。","ENG":"And yet you're still solving the mystery so easily... You never fail to surprise me.","TWN":"你卻還是這麼輕鬆地解開謎團……你總是讓我驚訝不已。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이래서야 자기가 각본 속에 있다는 걸 깨달아 버린 캐릭터와 다를 바 없네요.","JPN":"これでは自分が脚本の中にいるということに気づいてしまったキャラクターと変わらない。","ENG":"You're like a character who's realized they're part of a script.","TWN":"你就像個意識到自己是劇本一部分的角色。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"각본가로서는 썩 달갑지 않은 상황이네요.","JPN":"脚本家としてはあまり望ましくない状況です。","ENG":"Not something a scriptwriter would be thrilled about.","TWN":"可不是那種編劇會開心看到的事。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 글쎄?","JPN":"ふふ、それはどうかな。","ENG":"Haha, perhaps.","TWN":"哈哈，或許吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"지금의 런던은 자네의 기억을 바탕으로 구성된 작은 세계라고 해도 무방해.","JPN":"今のロンドンは君の記憶をもとに構成された小さな世界とみてもいい。","ENG":"This London might be a small world built from your memories.","TWN":"這個倫敦也許是個由你的記憶所構築的小世界。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 이건 아마도 자네의 인식이 나를 높게 평가하고 있어서 그런 것 아닐까?","JPN":"だとしたら、君の認識は私を高く評価しているという意味ではないか？","ENG":"But maybe it's because you hold me in such high regard that I turned out this sharp?","TWN":"但說不定正因為你把我看得如此重要，我才會變得這麼機靈？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이래봬도 나는 스스로를 꽤 평범한 사람이라고 생각하거든.","JPN":"こう見えて、私は自分を至極普通の人間だと思っているからね。","ENG":"I've always thought of myself as a pretty average fellow, you know.","TWN":"我一直覺得自己只是個平凡的人而已，你知道的。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그야 당연히 그렇겠죠.","JPN":"もちろんそうでしょう。","ENG":"Naturally.","TWN":"那是當然。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제 기억 속의 당신은 언제나 우아한 백조였는 걸.","JPN":"私の記憶の中のあなたはいつも優雅な白鳥だったもの。","ENG":"You were always a graceful swan in my memory.","TWN":"在我的記憶裡，你一直是優雅的天鵝。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"백조……?","JPN":"白鳥……？","ENG":"A swan...?","TWN":"天鵝？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 거기까지 추리했다면 당신도 알고 있을 텐데요?","JPN":"でもそこまで推理したのなら、あなたもわかっているはずです。","ENG":"But if you've figured out this much, then you must already know.","TWN":"但是如果你推理到那一步，你也應該知道吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금의 저는 딱히 감동의 재회를 하려고 온 게 아니라는 것쯤은 말이죠.","JPN":"今の私は感動の再会のために来たわけではないということくらいは。","ENG":"I'm not here for some touching reunion.","TWN":"我不是來這裡為了什麼感人的重逢。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론이라네, 스완.","JPN":"もちろんさ、スワン。","ENG":"Of course, Swan.","TWN":"當然了，史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아니, 지금은 이 세계를 무너트리려는 심야의 살인마라고 불러야 할까?","JPN":"いや、今はこの世界を滅ぼそうとしている深夜の殺人鬼と呼ぶべきかな？","ENG":"Or should I call you the Midnight Killer, the one trying to destroy this world?","TWN":"或者我該叫你午夜殺人魔，那個想要毀滅這個世界的人？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですね。","ENG":"...I see.","TWN":"……我明白了。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무리 제 기억 속 허상에 불과한 존재라고 할지라도 당신은 탐정.","JPN":"たとえ、記憶の中の虚像に過ぎない存在だとしても、あなたは探偵。","ENG":"Even if you're just an illusion of my memory, you're still a detective.","TWN":"即使你只是我記憶中的幻影，你依然是位偵探。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 당신의 적은 이 세계에 존재하는 모든 미지.","JPN":"そしてあなたの敵はこの世界に存在する全ての未知。","ENG":"And your enemy is everything unknown in this world.","TWN":"而你的敵人，是這個世界上一切未知的事物。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 모든 것이 당신을 위해서라고 할지라도, 당신은 틀림없이 제 앞을 막아설 모양이로군요.","JPN":"この世界全てがあなたのためだとしても、あなたは必ず私を邪魔するでしょう。","ENG":"Even if all this was meant for you, I guess you'll still stand in my way.","TWN":"即使這一切都是為了你，我想你仍會阻擋我。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 모든 것은 각본대로…….","JPN":"ですが、すべては脚本どおりに……","ENG":"But everything according to the script...","TWN":"但一切都依照劇本……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비록 도시 하나뿐인 세계에 불과하더라도 이 세계는 제가 구상한 각본이랍니다.","JPN":"たとえ都市一つ限りの世界だとしても、この世界は私が構想した脚本です。","ENG":"Even if this world only contains a single city, it still follows the script I wrote.","TWN":"即使這個世界只包含一座城市，也仍遵循我所寫的劇本。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무리 당신이라고 해도… 설마, 캐릭터 주제에 각본가를 이길 수 있다고 생각하는 건가요?","JPN":"いくらあなたでも……キャラクターの分際で、脚本家に勝てると思っているのですか？","ENG":"Do you really think a character... could surpass the one who wrote the story?","TWN":"你真的認為一個角色……能超越那個寫故事的人嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네, 스완.","JPN":"そのとおりだ、スワン。","ENG":"I do, Swan.","TWN":"我相信，史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"비록 지금의 나는 자네의 말대로 허상뿐일 존재에 불과하겠지만…….","JPN":"今の私は君の言うとおり、虚像の存在に過ぎないが……","ENG":"Even if I'm nothing more than an illusion, like you said...","TWN":"即使我不過是個幻影，像你說的那樣……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그럼에도 나는 자네를 막아 볼 생각이야.","JPN":"それでも、私は君を阻止してみるつもりだ。","ENG":"I still intend to stop you.","TWN":"我仍然打算阻止你。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면 자네가 이런 선택을 하게 된 건, 틀림없이 내 과오로부터 기인한 것일 테니까.","JPN":"君がこんな選択をするようになったのは、私の過ちに起因するものであることは間違いないからな。","ENG":"Because the choices you've made are probably the result of my own mistakes.","TWN":"因為你所做的選擇，很可能是我自己犯錯的結果。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"줄곧, 내가 자네에게 진실을 전하는 걸 망설였기 때문일 테니까.","JPN":"ずっと、私が君に真実を伝えることをためらっていたせいだから。","ENG":"Because I hesitated to tell you the truth all this time.","TWN":"因為我一直猶豫不決，不敢告訴你真相。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 이번만큼은 자네를 외면하지 않고 똑바로 자네와 마주해야겠지.","JPN":"だから今回だけはきちんと、君と向き合うべきだろう。","ENG":"So this time, I won't turn away. I'll face you head-on.","TWN":"所以這一次，我不會逃避。我要正面迎戰你。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네가 지난 꿈에서 깨어날 수 있도록… 오랜 노스탤지어에서 벗어날 수 있도록…….","JPN":"君が過ぎた夢から目覚められるように……長年のノスタルジアから抜け出せるように……","ENG":"So you can finally wake from that long dream... and escape your nostalgia...","TWN":"讓你終於從那漫長的夢境"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내가 자네에게 손을 건네도 괜찮을까?","JPN":"私が君に手を伸べてもいいかね？","ENG":"May I reach out my hand to you?","TWN":"我可以向你伸出手嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……아이린 애들러. 강철 같은 영혼을 가진 아름다운 여인이여.","JPN":"……アイリーン・アドラー。鋼のような魂を持つ美しい女性よ。","ENG":"...Irene Adler. You are a beautiful woman with a soul of steel.","TWN":"……愛琳·艾德勒。擁有鋼鐵般靈魂的美麗女人。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 이름…….","JPN":"その名前……","ENG":"That name...","TWN":"那個名字……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요. 저는 당신의 대답을 알고 있지만.","JPN":"そうですね。私はあなたの答えを知っていますが。","ENG":"I see. I already know what you'll say.","TWN":"原來如此。雖然我知道你的回答。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 당신에게 묻고 싶습니다. 프레드릭 애버라인.","JPN":"それでもあなたに尋ねたいです。フレデリック・アバーライン。","ENG":"But I still want to ask you, Frederick Abberline.","TWN":"儘管如此，我還是想問你，弗雷德里克·艾伯林。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은… 이런 저를 책망하시나요……?","JPN":"あなたは……こんな私を責めますか……？","ENG":"Do you... resent me for what I've become...?","TWN":"你是……在責怪這樣的我嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그럴 리가.","JPN":"ふふ、まさか。","ENG":"Haha, not at all.","TWN":"呵呵，怎麼可能。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"내가 어떻게 자네를 탓하겠나, 아이린.","JPN":"私が君を責めるわけがないだろう、アイリーン。","ENG":"How could I ever blame you, Irene?","TWN":"我怎麼會責怪你呢，愛琳。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"틀림없이 자네는 자네 나름대로 애써왔을 텐데 말이지.","JPN":"君は君なりに頑張ってきたはずなのに。","ENG":"You've done your best in your own way, haven't you?","TWN":"你只是用你自己的方式，盡了全力，不是嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잘못된 선택을 했다면, 고쳐 나가면 돼. 죄를 저질렀다면 그만큼 몇 번이고 속죄하게.","JPN":"間違った選択をしたなら、直していけばいい。罪を犯したのなら、その分、何度でも償いたまえ。","ENG":"If you made a mistake, then correct it. If you sinned, then atone for it.","TWN":"如果你犯了錯，就去改正它。如果你有罪，就去贖罪。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그걸 알려주기 위해서라도, 나는 이 자리에서 자네의 계획을 저지하겠어, 아이린.","JPN":"それを教えるためにも、私はこの場で君の計画を阻止する、アイリーン。","ENG":"To help you realize that, I'll stop your plan here, Irene.","TWN":"為了讓你明白這一點，我會在這裡阻止你的計畫，愛琳。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"왜냐하면 자네는 언제 어디서든 내 소중한 파트너니까.","JPN":"君はいつ、どこでも、私の大切なパートナーだからな。","ENG":"Because no matter what, you'll always be my precious partner.","TWN":"因為無論如何，你永遠是我珍貴的搭檔。"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"파트너…….","JPN":"パートナー……","ENG":"Partner...","TWN":"搭檔……"},"stage":{"bg":"CORRIDOR_09","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 여전히 당신답네요, 애버라인.","JPN":"ふふ、あなたらしいですね、アバーライン。","ENG":"Haha, you really haven't changed, Abberline.","TWN":"哈哈，你真的沒變，艾伯林。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금까지의 만담은 시간을 벌어볼 속셈이었군요.","JPN":"ここまでの茶番は時間稼ぎでしたか。","ENG":"This whole speech was just to buy time, wasn't it?","TWN":"這一大段話不過是為了拖時間，對吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아무래도 불청객이 도착한 모양이니까.","JPN":"どうやら招かれざる客が到着したようです。","ENG":"Looks like unwanted guests have arrived.","TWN":"看來不速之客到了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하하, 이거 들켜버렸군.","JPN":"はは、バレてしまったか。","ENG":"Haha, you caught me.","TWN":"哈哈，你抓到我了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 내 말은 한 치의 거짓 없는 진심일세.","JPN":"だが、私の言ったことは嘘偽りのない本心だ。","ENG":"But I meant every word I said.","TWN":"不過我說的每一句話都是認真的。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇겠죠. 설령, 이 순간이 제 미련이 남긴 잔상에 불과할지라도…….","JPN":"そうでしょうね。たとえ、この瞬間が私の未練から生まれた残像に過ぎないとしても……","ENG":"I believe you. Even if this moment is nothing but a leftover trace of my regret...","TWN":"我相信你。即使這一刻不過是我遺憾的殘留痕跡……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오랜만에 나눈 즐거운 만담이었어요.","JPN":"久々に楽しい茶番でした。","ENG":"It was nice catching up after all this time.","TWN":"畢竟，這麼久後能再敘舊真好。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"홍차가 없는 게 아쉽군요.","JPN":"紅茶がないのが残念ですね。","ENG":"Shame there's no tea to go with it.","TWN":"可惜沒有紅茶。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 미안하지만, 난 홍차보단 커피파라서.","JPN":"すまないが私は紅茶よりはコーヒー派なのでね。","ENG":"Haha, sorry, but I'm more of a coffee guy.","TWN":"哈哈，抱歉，我比較喜歡喝咖啡。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후후, 역시 당신이라는 사람은…….","JPN":"ふふ、やはりあなたという人は……","ENG":"Haha, you really are...","TWN":"呵呵，果然你這個人……"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"드디어 잡았다, 이 망할 년……!","JPN":"やっと捕まえた、このクソ女……！","ENG":"Got you at last, you damn woman...!","TWN":"終於抓住了，你這個該死的女人！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너 하나 잡겠다고 우리가 얼마나 생고생한 지 알기나 해……!?","JPN":"あんたを捕まえようと、あたしらがどれだけ苦労したと思ってんの……！！","ENG":"Do you have any idea how much we went through just to catch you...?!","TWN":"為了抓住你，你知道我們到底吃了多少苦頭嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"리트리버, 아무래도 제 훈육이 부족했던 모양이로군요.","JPN":"レトリーバー、どうやら私のしつけが足りなかったようですね。","ENG":"Retriever, seems I didn't train you well enough after all.","TWN":"獵犬，看起來是我對你的訓練不夠啊。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그때처럼 다치기 싫다면, 끼어들지 말고, 얌전히 비켜주시겠어요?","JPN":"あの時のように怪我したくないなら、ちょっかいを出さずに大人しくどいていてもらえませんか？","ENG":"If you don't want to get hurt like last time, I suggest you step aside.","TWN":"如果不想像那時候一樣受傷的話，就請不要插手，乖乖讓開好嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시끄러워! 같은 수법에 몇 번씩이나 당해줄 것 같아!?","JPN":"うるさい！　同じ手口に何度も引っかかるか！！","ENG":"Shut up! You think I'm falling for that trick again?!","TWN":"吵死了！？以為我會一直被同樣的招數打敗嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"벗이여, 갑자기 멋대로 뛰어나가더니 이게 대체 어떻게 된 일인가……?","JPN":"友よ、いきなり飛び出して、これはいったいどういうことだ……？","ENG":"My friend, you dashed off without warning. What is going on here...?","TWN":"朋友，你怎麼突然自己跑出去了，這到底是怎麼回事？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 이방인과 대치하고 있는 저 여자는 대체 누구지?","JPN":"それに、異邦人と対峙しているあの女性は誰なんだ？","ENG":"And who is that woman confronting the outsider?","TWN":"還有那個和外邦人對峙的女人到底是誰啊？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"움직임을 보니, 이능력자인 것 같은데……?","JPN":"動きからすると、異能力者のようだが……？","ENG":"Looking at her movements, she's clearly a supernatural...","TWN":"看這動作，似乎是個超能力者？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완이라네.","JPN":"スワンだ。","ENG":"That's Swan.","TWN":"她叫史旺。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 지금은 심야의 살인마이기도 하지…….","JPN":"今は深夜の殺人鬼でもある……","ENG":"And right now she's also the Midnight Killer...","TWN":"而現在也是午夜殺人魔……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"저 여자가… 스완이라고……?","JPN":"あの女性が……スワンだと……？","ENG":"That woman is... Swan...?","TWN":"那個女人是……史旺？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다네.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"정확한 표현은 아니지만, 우리 입장에서는 스완의 미래 모습이라고 할 수 있겠군.","JPN":"正確な表現ではないが、私たちから見れば、スワンの未来の姿と言えるだろう。","ENG":"It's not a perfect description, but from our perspective, she's Swan's future self.","TWN":"雖然這不是準確的說法，但從我們的立場來看，可以說是史旺的未來形象。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 소리죠……?","JPN":"どういうことですか……？","ENG":"What are you talking about...?","TWN":"這是什麼意思？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"지금 저 칼을 든 여자가… 미래의 저라고요……?","JPN":"今、あのナイフを突き出している女が……未来の私……？","ENG":"That woman with the knife... is supposed to be my future self...?","TWN":"那個拿著刀的女人……是未來的我嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"거기까지야, 스완……!","JPN":"そこまでだよ、スワン……！","ENG":"That's enough, Swan...!","TWN":"到此為止了，史旺！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"네가 이곳에서 무슨 짓을 꾸미는 지는 모르겠지만, 이제 다 끝났어……!","JPN":"あなたがここで何を企んでるのか知らないけど、もう終わりだ……！","ENG":"I don't know what you're planning here, but it's all over...!","TWN":"我不知道你在這裡策劃什麼？但現在一切都結束了！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"오랜만이로군요, 늑대.","JPN":"久しぶりです、オオカミ。","ENG":"It's been a while, Wolf.","TWN":"好久不見啊，狼。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"보아하니, 이제 상처를 회복한 모양이로군요.","JPN":"見たところ、もう怪我は治ったようですね。","ENG":"Looks like you've recovered from your injuries.","TWN":"看來，你的傷已經痊癒了。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래! 아무리 너라고 해도, 만전인 우리 둘을 상대로 이길 수 있을 것 같아?","JPN":"そう！　いくらあなたでも、本調子の私たち2人を相手に勝てると思う？","ENG":"Yeah! And no matter who you are, you're not beating both of us at full strength!","TWN":"對！算是你，也不可能戰勝我們兩個全力以赴的人吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"만전? 그거 재밌군요.","JPN":"本調子？　それは面白いですね。","ENG":"Full strength? Now that's amusing.","TWN":"全力以赴？那可有趣了。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋은 말로 할 때 대답해, 스완!","JPN":"いいから答えて、スワン！","ENG":"I'll ask nicely one last time. Answer me, Swan!","TWN":"趁我還好聲好氣地問的時候，好好回答我，史旺！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘은 지금 어디에 있지…? 노엘한테 무슨 짓을 한 거야……!","JPN":"ノエルは今どこにいる……？　ノエルに何をしたの……！","ENG":"Where's Noelle...? What did you do to her...?!","TWN":"洛艾兒現在在哪裡？你對洛艾兒做了什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"노엘이라…….","JPN":"ノエル……","ENG":"Noelle...","TWN":"洛艾兒啊……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"여기까지 왔다면, 당신도 이미 진실을 알고 있을 텐데요?","JPN":"ここまで来たのなら、あなたもすでに真実を知っているはずです。","ENG":"If you've made it this far, you must already know the truth.","TWN":"既然來到這裡，你應該也已經知道真相了吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"노엘 라이트라는 소녀는 이미 20년 전에 죽어버린 가련한 소녀에 불과하다는 걸 말이죠.","JPN":"ノエル・ライトという少女は、もう20年も前に死んでしまった可哀想な少女に過ぎないということを。","ENG":"That the girl known as Noelle Wright died twenty years ago.","TWN":"洛艾兒·萊特只不過是20年前就已經死去的可憐的少女而已。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 노엘이라고 생각하는 그 아이는 그저 껍데기에 불과한 존재입니다.","JPN":"あなたがノエルだと思っているあの子は、ただの殻です。","ENG":"The one you think is Noelle is just an empty shell.","TWN":"你所認為是洛艾兒的那個孩子，只不過是一個空殼而已。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그게 아니라면, 설마 진실을 외면할 셈인가요?","JPN":"それとも、まさか真実から目を背けるつもりですか？","ENG":"Or are you trying to deny the truth?","TWN":"難道說你打算無視真相嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"껍데기라고? 웃기지 마……!","JPN":"殻だと？　ふざけるな……！","ENG":"An empty shell? Don't make me laugh...!","TWN":"空殼？別說笑了！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘은 노엘이야! 펜릴 소대의 신입이자 내 후배일 뿐이라고……!","JPN":"ノエルはノエルだ！　フェンリル小隊の新入りで、私の後輩の……！","ENG":"Noelle is Noelle! She's the rookie of Fenrir Squad and my junior...!","TWN":"洛艾兒就是洛艾兒！是芬里爾小隊的新成員，也是我的後輩！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 과연 저 모습을 보고도 그렇게 말할 수 있을까요?","JPN":"どうでしょう。あの姿を見てもそう言えますか？","ENG":"Is that really what you believe after seeing her like that?","TWN":"是嗎？看到那種情景後，你還能這樣說嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"え……？","ENG":"What...?","TWN":"你說什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘……!!","JPN":"ノエル……！！","ENG":"Noelle...!!","TWN":"洛艾兒！？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이게 무슨 짓이야! 비켜……!!","JPN":"どういうつもりだ！　そこをどけ……！！","ENG":"What did you do to her?! Get out of my way...!!","TWN":"你這是在幹什麼？讓開！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아쉽지만, 아직은 이 아이에게 접근하게 둘 수 없답니다, 늑대.","JPN":"残念ですが、まだこの子に近づかせるわけにはいきません、オオカミ。","ENG":"Sorry, but I can't let you near her just yet, Wolf.","TWN":"很遺憾，現在還不能讓你接近這個孩子，狼。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 이 아이는 진정한 <color=#ffd34c>천사 강림</color>의 제물이 되어야 하거든요.","JPN":"この子は真なる<color=#ffd34c>天使降臨</color>の生贄となってもらわねばなりませんから。","ENG":"Because she's the chosen sacrifice for the true <color=#ffd34c>angel's descent</color>.","TWN":"因為這個孩子才是真正的<color=#ffd34c>天使降臨</color>的祭品。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"천사 강림이라고……?","JPN":"天使降臨だって……？","ENG":"Angel's descent...?","TWN":"天使降臨？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 예상했겠지만, 이 아이의 본질은 <color=#ffd34c>세피라</color>.","JPN":"あなたも予想していたでしょうが、この子の本質は<color=#ffd34c>セフィラ</color>。","ENG":"You probably suspected it, but this girl's essence is <color=#ffd34c>Sephira</color>.","TWN":"你可能已經猜到了，這個孩子就是<color=#ffd34c>生命樹</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>세계를 만드는 법칙</color>에서 떨어져 나온 일부라고 할 수 있답니다.","JPN":"<color=#ffd34c>世界を作る法則</color>から抜け落ちた一部だと言えるのです。","ENG":"She's a fragment torn from <color=#ffd34c>the law of creating a world</color>.","TWN":"可以說是從<color=#ffd34c>創造世界的法則</color>中脫離出來的一部分。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L9_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"잠깐, 무슨 헛소리야? 저 꼬맹이가 세피라라고……?","JPN":"待てよ、どういうこと？　あのガキがセフィラ……？","ENG":"Hold on, what are you rambling about? That kid is Sephira...?","TWN":"等等，你在胡說什麼？那個小鬼是生命樹？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그럼… 멸망해버린 네 세계를 되돌린 게, 저 꼬맹이의 힘이라는 뜻이야……?","JPN":"じゃあ……滅亡してしまったあんたの世界を元に戻したのが、あの子の力だってこと……？","ENG":"Then... you're saying the one who brought back your ruined world was her...?","TWN":"所以說……把你那個已經毀滅的世界恢復原狀的是那個小鬼的力量嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아아, 당신은 아직 모르고 있었군요, 리트리버.","JPN":"ああ、あなたはまだ知らなかったのですね、レトリーバー。","ENG":"Ah, so you don't know yet, Retriever.","TWN":"你還不知道嗎，獵犬。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니, 어쩌면 이것도 그 잘난 대장님께서 진실을 함구한 걸까요?","JPN":"いいえ、もしかしたらこれもあの隊長が真実を隠しているからでしょうか。","ENG":"Or maybe your oh-so-honest Commander kept the truth from you again?","TWN":"不，或許這也是那位自以為是的隊長隱瞞了真相吧？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L17_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"시끄러워, 이 박쥐 같은 게……!","JPN":"うるさい、このコウモリが……！","ENG":"Shut it, you damn bat...!","TWN":"閉嘴，你這個像蝙蝠一樣的傢伙！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그런 이간질에 두 번이나 넘어갈 것 같아?","JPN":"そんな工作に二度も引っかからないよ。","ENG":"You think I'm falling for your mind games a second time?!","TWN":"你以為挑撥離間的當我會上兩遍嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 이간질이라…….","JPN":"さて、工作とは……","ENG":"Mind games, is it...","TWN":"這個嘛，挑撥離間……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"에이미, 당신과 목격했던 현실 개변은 이 아이가 현실에 강림하면서 발생한 여파였어요.","JPN":"エイミー、あなたが目撃した現実改変は、この子が現実世界に降臨した際に発生した余波でした。","ENG":"Amy, the change in reality we witnessed was the result of this girl descending into the real world.","TWN":"艾米，你和我目擊到的現實變更，是因為這個孩子降臨到現實中所引發的餘波。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 저는 마침내 이 아이의 힘을 다룰 수 있는 방법을 찾아냈답니다.","JPN":"そして、私はついにこの子の力を扱う方法を見つけたのです。","ENG":"And now, I've finally discovered how to control her power.","TWN":"而且我終於找到了掌控這個孩子力量的方法。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"어이, 잠깐! 유미나!","JPN":"おい、！　ミナ！","ENG":"Hey, hold on! Yoo Mina!","TWN":"喂，等一下！劉米娜！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"너, 알고 있었어? 세피라의 정체가 저 꼬맹이라는 걸 알고 있었냐고!","JPN":"あんた、知ってたのか？　セフィラの正体があのガキだってこと、知ってたのかよ！","ENG":"You knew, didn't you? You knew that little brat was the Sephira all along!","TWN":"你，早就知道了？你知道生命樹的真面目是那個小鬼嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"……그래, 알고 있었어.","JPN":"……うん、知ってた。","ENG":"...Yeah. I knew.","TWN":"……對，我知道。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"현실에서 노엘이 사라진 뒤로, 현실에 정보 말소 현상이 일어났거든.","JPN":"現実からノエルが消えた後、情報抹消現象が起こったんだ。","ENG":"After Noelle vanished from reality, information erasure started happening too.","TWN":"自從洛艾兒在現實中消失後，現實中就發生了資訊抹消現象。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"정보 말소라고……?","JPN":"情報抹消だと……？","ENG":"Information erasure...?","TWN":"資訊抹消嗎？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래. 그래서 나 말고는 그 누구도 노엘을 기억하지 못하게 됐으니까.","JPN":"そう。私以外は誰もノエルのことを記憶できなくなっていたから。","ENG":"Yes. After that, no one but me could remember her.","TWN":"是。所以除了我，沒有人能記得洛艾兒了。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"적어도 스완이 노엘을 납치했기 때문에 그런 현상이 발생했다는 건 이미 알고 있었어.","JPN":"少なくともスワンがノエルを誘拐したせいでそんな現象が発生した、ってことは知ってた。","ENG":"At the very least, I already knew Swan kidnapped Noelle and that's what caused all this.","TWN":"至少我們已經知道，因為史旺綁架了洛艾兒，所以才發生了那種現象。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해도 이건 뭔가 이상해.","JPN":"でも、そうだとしても、おかしいよ。","ENG":"But even knowing that, something doesn't add up.","TWN":"但是就算這麼說，這也有點奇怪。"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘이 저렇게 순순히 스완의 명령을 따를 리가 없다고!","JPN":"ノエルはあんな大人しくスワンの命令に従うわけがないんだ！","ENG":"Noelle would never just follow Swan's orders like that!","TWN":"洛艾兒不可能那麼乖乖地聽從史旺的命令！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"대답해, 스완!","JPN":"答えて、スワン！","ENG":"Answer me, Swan!","TWN":"回答我，史旺！"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노엘에게 대체 무슨 짓을 한 거야……!?","JPN":"ノエルにいったい何をした……！？","ENG":"What did you do to Noelle...?!","TWN":"你對洛艾兒到底做了什麼？？"},"stage":{"bg":"CORRIDOR_09","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그건 간단한 이야기랍니다, 늑대.","JPN":"簡単な話ですよ、オオカミ。","ENG":"It's quite simple, Wolf.","TWN":"那是個簡單的故事，狼。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 아이의 본질은 세계를 만드는 법칙의 일부…….","JPN":"この子の本質は世界を作る法則の一部……","ENG":"This girl is part of the law of creating a world...","TWN":"這個孩子的本質是創造世界法則的一部分……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"따라서 이 아이가 진심으로 믿는 것은 그게 무엇이든 현실이 되어버리죠.","JPN":"つまり、この子が本心から信じていることは、それがどんなことでも現実になってしまう。","ENG":"Which means whatever she truly believes becomes reality.","TWN":"因此，只要是這個孩子真心相信的東西，無論是什麼？都會變成現實。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 저를 따르는 것 이외의 모든 선택지를 제거했을 뿐입니다.","JPN":"だから、私に従う以外の全ての選択肢を除外しただけです。","ENG":"So I just removed every option except following me.","TWN":"所以我只是刪掉了除了跟隨我以外的所有選項。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"인간으로서 이 아이의 <color=#ffd34c>존엄</color>을 짓밟아서 말이죠.","JPN":"人間としてのこの子の<color=#ffd34c>尊厳</color>を踏みにじって。","ENG":"By crushing her human <color=#ffd34c>dignity</color>, that is.","TWN":"踐踏了這個孩子作為人類的<color=#ffd34c>尊嚴</color>。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"존엄을 짓밟아…? 그게 무슨 헛소리야……!","JPN":"尊厳を踏みにじる……？　ノエルに……ノエルに何をした！","ENG":"Crushing her dignity...? What kind of twisted logic is that...?!","TWN":"踐踏尊嚴？你在胡說八道什麼？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기억도, 이성도, 그리고 당신을 향한 감정도…….","JPN":"記憶も、理性も、そしてあなたへの感情も……","ENG":"Her memories, her reasoning, even her feelings for you...","TWN":"記憶、理智，還有對你的感情……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"지금 이 아이의 머릿속은 텅 비어 버려서, 그 어떤 것도 남아있지 않아요.","JPN":"今この子の頭の中は空っぽで、何も残っていません。","ENG":"Her mind is completely blank now. There's nothing left.","TWN":"現在這個孩子的腦袋裡空空如也，什麼都沒有留下。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그저 제가 보여주고 있는 각본을 끊임없이 현실로 재구성하고 있을 뿐이죠.","JPN":"ただただ、私が見せる脚本を絶え間なく、現実として再構成しているだけです。","ENG":"All she's doing is projecting the script I feed her, over and over into reality.","TWN":"她只是在不斷地將我展示的劇本重新構建成現實而已。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 비유하자면, 영화 카메라라고 할까요?","JPN":"そう。例えるなら、プロジェクターといったところでしょうか。","ENG":"If I had to put it in metaphor... I'd call her a movie camera.","TWN":"是的。打個比方，就像電影攝影機一樣？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 아이는 결말이 정해진 영화를 스크린에 비춰주는 영사기라고 할 수 있답니다.","JPN":"この子は結末が定められた映画をスクリーンに映し出す、映写機だと言えます。","ENG":"She is like a projector, casting a film whose ending has already been decided.","TWN":"這個孩子就像是一台放映機，把已經註定結局的電影投射到螢幕上。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"영화 카메라라고……?","JPN":"プロジェクター……？","ENG":"A movie camera...?","TWN":"電影攝影機？"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"걱정하지 마세요, 늑대.","JPN":"心配する必要はありません、オオカミ。","ENG":"Don't worry, Wolf.","TWN":"不用擔心，狼。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くうっ……！","ENG":"Krrgh...!","TWN":"呃！"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SWORD_HIT"},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"어차피 모든 것은 각본대로…….","JPN":"どうせすべては脚本どおりに……","ENG":"Still, everything according to the script...","TWN":"反正一切都將按照劇本進行……"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아직 각본이 엔딩에 다다르기에는 시간이 조금 남았습니다.","JPN":"まだ脚本がエンディングを迎えるまでには時間があります。","ENG":"The ending for the script still isn't quite here yet.","TWN":"距離劇本結局還有一點時間。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 함께 발맞춰 춤을 춰드리죠.","JPN":"ですから、一緒に踊りましょう。","ENG":"So let's dance together, in step.","TWN":"那麼就讓我與你共舞吧。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"우리에게 어떤 엔딩이 기다릴지 손꼽아 기다리면서.","JPN":"どんなエンディングが待っているのか、心待ちにしながら。","ENG":"While we count down to see what kind of ending awaits us.","TWN":"期待著我們會迎來怎樣的結局。"},"stage":{"bg":"CORRIDOR_09","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};